def _sanitize_key(key: str) -> str:
    """Sanitize Redis keys to prevent injection attacks."""
    # Only allow alphanumeric characters, underscores, hyphens, and colons
    sanitized = "".join(c for c in key if c.isalnum() or c in ("_", "-", ":", "."))
    if not sanitized:
        raise ValueError("Invalid key after sanitization")
    return sanitized


def _hash_token(token: str) -> str:
    """Hash session tokens before using as Redis keys to prevent timing attacks."""
    return hashlib.sha256(token.encode("utf-8")).hexdigest()


