            if session_data:
                user_id = session_data.get("user_id")
                pipe = self.redis.pipeline(transaction=True)
                pipe.delete(session_key)
                if user_id:
                    user_sessions_key = f"{self.USER_SESSIONS_PREFIX}{user_id}"
