# --- Caching Decorator ---

def cache_result(
    ttl: int = CACHE_DEFAULT_TTL,
    prefix: str = "cache",
    key_builder: Optional[Callable] = None,
):
    """
    Caching decorator for expensive operations.
    
    Args:
        ttl: Time-to-live in seconds for cached results.
        prefix: Prefix for cache keys.
        key_builder: Optional custom function to build cache keys.
    """
    def decorator(func: Callable) -> Callable:
        @functools.wraps(func)
        def wrapper(*args, **kwargs) -> Any:
            # Build cache key
            if key_builder:
                raw_key = key_builder(*args, **kwargs)
            else:
                # Create a deterministic key from function name and arguments
                key_parts = [func.__module__, func.__qualname__]
                
                # Serialize arguments safely
                for arg in args:
                    key_parts.append(repr(arg))
                for k, v in sorted(kwargs.items()):
                    key_parts.append(f"{k}={repr(v)}")
                
                raw_key = ":".join(key_parts)

            # Hash the key to prevent overly long keys and injection
            key_hash = hashlib.sha256(raw_key.encode("utf-8")).hexdigest()
            cache_key = f"{_sanitize_key(prefix)}:{func.__qualname__}:{key_hash}"

            # Try to get from cache
            try:
                cached_value = redis_client.get(cache_key)
                if cached_value is not None:
                    logger.debug(f"Cache hit for {func.__qualname__}")
                    return json.loads(cached_value)
            except redis.RedisError as e:
                logger.warning(f"Cache read error: {e}")
            except (json.JSONDecodeError, TypeError) as e:
                logger.warning(f"Cache deserialization error: {e}")

            # Execute function
            logger.debug(f"Cache miss for {func.__qualname__}")
            result = func(*args, **kwargs)

            # Store in cache
            try:
                serialized = json.dumps(result)
                # Limit cache value size (10MB)
                if len(serialized) <= 10 * 1024 * 1024:
                    redis_client.set(cache_key, serialized, ex=ttl)
                else:
                    logger.warning(f"Cache value too large for {func.__qualname__}")
            except (redis.RedisError, TypeError) as e:
                logger.warning(f"Cache write error: {e}")

            return result

        # Add cache invalidation method
        def invalidate(*args, **kwargs):
            """Invalidate the cache for specific arguments."""
            if key_builder:
                raw_key = key_builder(*args, **kwargs)
            else:
                key_parts = [func.__module__, func.__qualname__]
                for arg in args:
                    key_parts.append(repr(arg))
                for k, v in sorted(kwargs.items()):
                    key_parts.append(f"{k}={repr(v)}")
                raw_key = ":".join(key_parts)

            key_hash = hashlib.sha256(raw_key.encode("utf-8")).hexdigest()
            cache_key = f"{_sanitize_key(prefix)}:{func.__qualname__}:{key_hash}"

            try:
                redis_client.delete(cache_key)
                logger.info(f"Cache invalidated for {func.__qualname__}")
            except redis.RedisError as e:
                logger.warning(f"Cache invalidation error: {e}")

        wrapper.invalidate = invalidate
        return wrapper

    return decorator


def invalidate_cache_pattern(pattern_prefix: str):
    """Invalidate all cache entries matching a pattern. Use with caution."""
    sanitized_prefix = _sanitize_key(pattern_prefix)
    try:
        cursor = 0
        deleted_count = 0
        while True:
            cursor, keys = redis_client.scan(
                cursor=cursor,
                match=f"{sanitized_prefix}:*",
                count=100,
            )
            if keys:
                redis_client.delete(*keys)
                deleted_count += len(keys)
            if cursor == 0:
                break
        logger.info(f"Invalidated {deleted_count} cache entries with prefix {sanitized_prefix}")
        return deleted_count
    except redis.RedisError as e:
        logger.error(f"Cache pattern invalidation error: {e}")
        return 0


# --- Rate Limiting ---

def rate_limit(max_requests: int = 100, window_seconds: int = 60):
    """Simple rate limiting decorator using Redis."""
    def decorator(func: Callable) -> Callable:
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Use IP address for rate limiting
            client_ip = request.remote_addr or "unknown"
            rate_key = f"rate_limit:{_sanitize_key(func.__qualname__)}:{_sanitize_key(client_ip)}"

            try:
                pipe = redis_client.pipeline(transaction=True)
                pipe.incr(rate_key)
                pipe.ttl(rate_key)
                results = pipe.execute()

                current_count = results[0]
                current_ttl = results[1]

                # Set expiry on first request
                if current_ttl == -1:
                    redis_client.expire(rate_key, window_seconds)

                if current_count > max_requests:
                    logger.warning(f"Rate limit exceeded for {client_ip} on {func.__qualname__}")
                    return jsonify({
                        "error": "Rate limit exceeded",
                        "retry_after": current_ttl if current_ttl > 0 else window_seconds,
                    }), 429

            except redis.RedisError as e:
                logger.warning(f"Rate limiting error: {e}")
                # Fail open - allow request if Redis is down

            return func(*args, **kwargs)

        return wrapper
    return decorator


# --- Authentication Middleware ---

def require_session(func: Callable) -> Callable:
    """Middleware to require a valid session for protected endpoints."""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")

        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or invalid authorization header"}), 401

        token = auth_header[7:]  # Remove "Bearer " prefix

        if not token or len(token) > 256:
            return jsonify({"error": "Invalid token"}), 401

        session_data = session_manager.get_session(token)
        if not session_data:
            return jsonify({"error": "Invalid or expired session"}), 401

        # Store session data in Flask's g object for use in route handlers
        g.session_data = session_data
        g.user_id = session_data.get("user_id")
        g.session_token = token

        return func(*args, **kwargs)

    return wrapper


