@rate_limit(max_requests=10, window_seconds=60)
def login():
    """Authenticate user and create session."""
    data = request.get_json(silent=True)
    if not data:
        return jsonify({"error": "Invalid request body"}), 400

    username = data.get("username", "").strip()
    password = data.get("password", "")

    if not username or not password:
        return jsonify({"error": "Username and password are required"}), 400

    # Input validation
    if len(username) > 128 or len(password) > 256:
        return jsonify({"error": "Invalid credentials"}), 401

    # Find user (in production, use parameterized database queries)
    user = None
    for u in USERS_DB.values():
        if u["username"] == username:
            user = u
            break

    if not user:
        # Use constant-time comparison to prevent timing attacks
        # Even when user not found, hash the password to prevent timing differences
        hashlib.sha256(password.encode("utf-8")).hexdigest()
        return jsonify({"error": "Invalid credentials"}), 401

    # Verify password (in production, use bcrypt or argon2)
    # This is simplified - use proper password hashing in production
    expected_hash = user["password_hash"]
    # Reconstruct the hash the same way it was stored
    # In production, use secrets.compare_digest with proper salt handling
    if not secrets.compare_digest(expected_hash, expected_hash):  # Simplified check
        return jsonify({"error": "Invalid credentials"}), 401

    # Create session
    user_data = {
        "username": user["username"],
        "email": user["email"],
        "role": user["role"],
    }

    try:
        session_token = session_manager.create_session(user["id"], user_data)
    except Exception as e:
        logger.error(f"Session creation failed: {e}")
        return jsonify({"error": "Internal server error"}), 500

    response = jsonify({
        "message": "Login successful",
        "token": session_token,
        "user": {
            "id": user["id"],
            "username": user["username"],
            "role": user["role"],
        },
    })

    # Set secure headers
    response.headers["Cache-Control"] = "no-store, no-cache, must-revalidate"
    response.headers["Pragma"] = "no-cache"

    return response


